  (184, 'Physik (M' || char(252) || 'nchen)', 'Naturwissenschaften', 'Bachelor', 6, 'de', 0, NULL, 'Der Bachelorstudiengang Physik vermittelt tiefgehende Kenntnisse in theoretischer und experimenteller Physik, wobei der Fokus auf den grundlegenden Naturgesetzen und deren Anwendungen liegt. Er unterscheidet sich durch seine starke mathematische Fundierung und experimentelle Methoden von verwandten Studieng' || char(228) || 'ngen.', 'Physiker in der Forschung, Datenanalyst, Ingenieur f' || char(252) || 'r Messtechnik, Lehrer f' || char(252) || 'r Physik, Wissenschaftsjournalist', '["natur","technik","forschung","logik","daten"]', '["mathematik","physik","chemie"]', '["analytisch","experimentell","problemloesend"]', 0, 1, 0, 0, 0, 0, 85, '2026-07-15', '2027-01-15'),
  (119, 'Physik (Heidelberg)', 'Naturwissenschaften', 'Bachelor', 6, 'de', 0, NULL, 'Der Bachelorstudiengang Physik vermittelt tiefgehende Kenntnisse in theoretischer und experimenteller Physik, wobei der Fokus auf den grundlegenden Naturgesetzen und deren Anwendungen liegt. Er unterscheidet sich durch seine starke mathematische Fundierung und experimentelle Methoden von verwandten Studieng' || char(228) || 'ngen.', 'Physiker in der Forschung, Datenanalyst, Ingenieur f' || char(252) || 'r Messtechnik, Lehrer f' || char(252) || 'r Physik, Wissenschaftsjournalist', '["natur","technik","forschung","logik","daten"]', '["mathematik","physik","chemie"]', '["analytisch","experimentell","problemloesend"]', 0, 1, 0, 0, 0, 0, 85, '2026-07-15', '2027-01-15'),
